import { formatCurrency } from '@angular/common';
import { TranslateService } from '@ngx-translate/core';
import { isNullOrUndefined } from '../../../shared/utils';
import { FeeModel } from '../models/app-store.models';

/**
 * Builds the human-readable fee label. Free when there is no fee model, the
 * amount is null/undefined, OR the amount is zero (R0 = free) — the API contract
 * (feeModel.amount?: number | null) allows a typed-but-free fee, which the local
 * FeeModel type does not surface.
 */
export function getFeeLabel(feeModel: FeeModel | null, translateService: TranslateService): string {
  if (isNullOrUndefined(feeModel) || isNullOrUndefined(feeModel.amount) || feeModel.amount <= 0) {
    return translateService.instant('ADMIN.APP_STORE.FEE.FREE');
  }
  const amount = formatCurrency(feeModel.amount, 'en-ZA', 'R', 'ZAR');
  const key =
    feeModel.type === 'perInstallation'
      ? 'ADMIN.APP_STORE.FEE.PER_INSTALL'
      : 'ADMIN.APP_STORE.FEE.PER_ACTIVE_DEVICE';
  return translateService.instant(key, { amount });
}
