import { Component, input, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { AppVisibility } from '../../models/app-store.models';

@Component({
  selector: 'app-visibility-badge',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './app-visibility-badge.component.html',
  styleUrls: ['./app-visibility-badge.component.scss'],
})
export class AppVisibilityBadgeComponent {
  readonly visibility = input.required<AppVisibility>();

  readonly showBadge = computed(() => this.visibility() !== 'global');

  readonly label = computed(() => {
    switch (this.visibility()) {
      case 'ourOperations':
        return 'Our Operations';
      case 'unlisted':
        return 'Unlisted';
      default:
        return null;
    }
  });

  readonly badgeClass = computed(() => {
    switch (this.visibility()) {
      case 'ourOperations':
        return 'visibility-our-operations';
      case 'unlisted':
        return 'visibility-unlisted';
      default:
        return null;
    }
  });
}
